import Productos from './productos.js';


const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <BrowserRouter>

    <Navbar />
    <Routes>

      <Route path="index.html" element={<IndexFirst />} />
      <Route path="/productos.html" element={<Productos />} />
